# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import mimetypes
from pathlib import Path
from typing import Dict, Any, List, Optional

from fastapi import FastAPI, HTTPException, Query
from fastapi.responses import FileResponse, JSONResponse


app = FastAPI(title="File Explorer API", version="1.0.0")


def _safe_full_path(user_root: str, rel_path: Optional[str]) -> str:
    if rel_path is None:
        rel_path = ""
    rel_path = rel_path.replace("\x00", "")
    if os.path.isabs(rel_path):
        raise HTTPException(status_code=400, detail="Path must be relative to user root")

    root_abs = os.path.abspath(user_root)
    joined = os.path.join(root_abs, rel_path)
    normed = os.path.normpath(joined)
    full_abs = os.path.abspath(normed)

    try:
        common = os.path.commonpath([root_abs, full_abs])
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid path")

    if common != root_abs:
        raise HTTPException(status_code=403, detail="Path escapes user root")

    return full_abs


def _get_user_root(user_id: str) -> str:
    base = os.environ.get("UPLOADS_DIR", os.path.join(os.getcwd(), "uploads"))
    user_root = os.path.join(base, user_id)
    user_root = os.path.abspath(os.path.normpath(user_root))
    return user_root


def _stat_info(full_path: str, root_abs: str) -> Dict[str, Any]:
    st = os.stat(full_path, follow_symlinks=False)
    is_dir = os.path.isdir(full_path)
    is_file = os.path.isfile(full_path)
    is_symlink = os.path.islink(full_path)

    rel = os.path.relpath(full_path, root_abs)
    if rel == ".":
        rel = ""

    mime, _ = mimetypes.guess_type(full_path)
    info = {
        "path": rel.replace("\\", "/"),
        "name": os.path.basename(full_path) if rel else "",
        "type": "directory" if is_dir else "file" if is_file else "other",
        "is_dir": is_dir,
        "is_file": is_file,
        "is_symlink": is_symlink,
        "size": None if is_dir else st.st_size,
        "modified": int(st.st_mtime),
        "created": int(getattr(st, "st_ctime", st.st_mtime)),
        "mime": mime if is_file else None,
    }
    return info


@app.get("/users/{user_id}/list")
def list_directory(
    user_id: str,
    path: str = Query(default="", description="Directory path relative to user's root"),
) -> Dict[str, Any]:
    user_root = _get_user_root(user_id)
    if not os.path.isdir(user_root):
        raise HTTPException(status_code=404, detail="User root not found")

    full = _safe_full_path(user_root, path)
    if not os.path.exists(full):
        raise HTTPException(status_code=404, detail="Path not found")
    if not os.path.isdir(full):
        raise HTTPException(status_code=400, detail="Path is not a directory")

    root_abs = os.path.abspath(user_root)
    items: List[Dict[str, Any]] = []

    try:
        with os.scandir(full) as it:
            for entry in it:
                try:
                    entry_path = entry.path
                    info = _stat_info(entry_path, root_abs)
                    items.append(info)
                except FileNotFoundError:
                    continue
    except PermissionError:
        raise HTTPException(status_code=403, detail="Permission denied")

    items.sort(key=lambda x: (0 if x["is_dir"] else 1, x["name"].lower()))
    current = os.path.relpath(full, root_abs)
    if current == ".":
        current = ""
    current = current.replace("\\", "/")

    parent = None
    if current:
        parent = os.path.dirname(current).replace("\\", "/")
        if parent == ".":
            parent = ""

    return {"path": current, "parent": parent, "items": items}


@app.get("/users/{user_id}/download")
def download_file(
    user_id: str,
    path: str = Query(..., description="File path relative to user's root"),
) -> FileResponse:
    user_root = _get_user_root(user_id)
    if not os.path.isdir(user_root):
        raise HTTPException(status_code=404, detail="User root not found")

    full = _safe_full_path(user_root, path)
    if not os.path.exists(full):
        raise HTTPException(status_code=404, detail="File not found")
    if not os.path.isfile(full):
        raise HTTPException(status_code=400, detail="Path is not a file")

    mime, _ = mimetypes.guess_type(full)
    filename = os.path.basename(full)
    return FileResponse(full, media_type=mime or "application/octet-stream", filename=filename)


@app.get("/users/{user_id}/info")
def get_file_info(
    user_id: str,
    path: str = Query(default="", description="Path relative to user's root"),
) -> JSONResponse:
    user_root = _get_user_root(user_id)
    if not os.path.isdir(user_root):
        raise HTTPException(status_code=404, detail="User root not found")

    full = _safe_full_path(user_root, path)
    if not os.path.exists(full):
        raise HTTPException(status_code=404, detail="Path not found")

    root_abs = os.path.abspath(user_root)
    try:
        info = _stat_info(full, root_abs)
    except PermissionError:
        raise HTTPException(status_code=403, detail="Permission denied")

    return JSONResponse(info)


